+			icon = "❌"
+		}
+		sb.WriteString(fmt.Sprintf("- %s **%s**: %s (`%s:%d`)\n", icon, f.RuleID, f.Message, f.File, f.Line))
+	}
+
+	sb.WriteString("Please review and fix these issues.")
+	return sb.String()
